choose.when:
SELECT EXISTS(
  SELECT 1
  FROM sale_deal
  WHERE id = #{dealId}
    AND property_id = #{propertyId}
)

SELECT EXISTS(
  SELECT 1
  FROM rent_deal
  WHERE id = #{dealId}
    AND property_id = #{propertyId}
    AND monthly_rent = 0
)

choose.otherwise:
SELECT EXISTS(
  SELECT 1
  FROM rent_deal
  WHERE id = #{dealId}
    AND property_id = #{propertyId}
    AND monthly_rent > 0
)

mapper.select:
